VALUES
  ('social-worker-moex-03171', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社會工作研究者想瞭解接受安寧照護病患的經歷、以及這些經歷對患者的深層意義，來提高他們的生 活品質，這類研究較適合採用的典範是：', '["現代主義", "實證主義", "批判主義", "詮釋主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03172', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某人想藉由觀察團體成員彼此談話中「我們」一詞出現的次數來研究「團體凝聚力」。請問從「團體凝 聚力」到「團體成員對話過程中我們一詞出現的次數」，這個過程在研究法中叫：', '["概念化", "操作化", "抽象化", "量化研究不會出現這種做法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03173', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有位男性身處在以女性為主的社會工作專業中，每當他回答涉及性別議題的問卷時，總是小心翼翼，避 免自己變成男性沙文主義者。請問這種現象是：', '["社會期望的偏誤（social desirability bias）", "隨機性的誤差（random error）", "月暈效應（halo effect）", "順勢反應（acquiescent response set）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03174', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在實務工作中，我們常用非常滿意、滿意、普通、不滿意、非常不滿意來反應服務使用者的意見。姑不 論實際統計操作的權宜作法，它真正的測量尺度是：', '["類別尺度（nominal level）", "順序尺度（ordinal level）", "等距尺度（interval level）", "等比尺度（ratio level）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03175', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某異性戀研究者想研究同性戀者生活網絡，採用何種取樣方式方是合宜？', '["機率抽樣（probability sampling）", "限額抽樣（quota sampling ）", "理論抽樣（theoretical sampling）", "滾雪球抽樣（snowball sampling）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03176', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列量化研究中決定樣本大小的敘述，何者正確？', '["它可由「待分析變項數乘以統計程序所需每個變項之最小樣本數」所決定", "它可由「研究者所決定的抽樣間距（sampling interval）」所決定", "它可由「按數量成比例的機率抽樣（Probability Proportionate to Size Sampling，簡稱PPS）」所決定", "它可由「母群體越小、樣本就必需抽得越大」這項描述所決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03177', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者發現社區居民需求評量的量表中「社會融合」這項構面的Cronbach α值為0.82。這意味著：', '["這份量表的內容效度高，它可以真正測到社會融合這個構面", "這份量表的受測者在填答社會融合這個構面的不同題項時，它有著高度差異的反應", "這份量表中社會融合構面的建構效度高，它表示其中各個項目間具有高度的一致性", "這份量表在社會融合這項構面中的各個題項相關性高，它在信度上具有內在一致性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03178', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想研究報紙中低收入戶的公眾意象，這項研究的分析單位（unit of analysis）是：', '["記者本人", "低收入戶本人", "報紙的報導", "社會救助業務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03179', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對受霸凌學童，綜合運用諸如社會工作者的個案紀錄、兒童行為檢核表、學校導師紀錄、兒童綜合適 應量表…等多元測量工具來提升研究效度的方法叫：', '["詮釋循環法（hermeneutic circle）", "線性插補法（linear interpolation）", "已知團體效度法（known groups validity）", "三角測量法（triangulation）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03180', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某問卷之問項為「市長應該花更多納稅人的錢，來確保本市市民享有老人津貼的福利」。上述問項犯了 何種錯誤？', '["誘導性", "雙重否定", "事後回溯", "聲望偏誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
